import ollama

tools = [{
    "type": "function",
    "function": {
        "name": "get_stock_price",
        "description": "Get the current price for a stock ticker symbol",
        "parameters": {
            "type": "object",
            "properties": {"ticker": {"type": "string"}},
            "required": ["ticker"]
        }
    }
}]

def dispatch(name, args):
    if name == "get_stock_price":
        return {"ticker": args["ticker"], "price": 142.30}  # stub
    raise ValueError(f"Unknown tool: {name}")

def run_agent(prompt: str) -> str:
    messages = [{"role": "user", "content": prompt}]
    while True:
        res = ollama.chat(model="llama3.1", messages=messages, tools=tools)
        msg = res["message"]
        messages.append(msg)
        if not msg.get("tool_calls"):
            return msg["content"]
        for call in msg["tool_calls"]:
            result = dispatch(call["function"]["name"], call["function"]["arguments"])
            messages.append({"role": "tool", "content": str(result)})

print(run_agent("What is the price of AAPL?"))

import ollama

def summarize_history(messages: list) -> str:
    text = "\n".join(f"{m['role']}: {m['content']}" for m in messages)
    resp = ollama.chat("llama3.2:1b", messages=[
        {"role": "user", "content": f"Summarize in 2 sentences:\n{text}"}
    ], options={"num_ctx": 4096})
    return resp["message"]["content"]

def compress_and_chat(history: list, user_msg: str) -> str:
    if len(history) > 8:
        summary = summarize_history(history[:-2])
        history = [{"role": "system", "content": f"Prior context: {summary}"}] + history[-2:]
    history.append({"role": "user", "content": user_msg})
    resp = ollama.chat("llama3.2", messages=history, options={"num_ctx": 8192})
    history.append(resp["message"])
    return resp["message"]["content"]
